module RefModule (
  input clk,
  input en,
  input rst,
  input [7:0] d,
  output reg [7:0] acc);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        acc <= 8'b0;
    else if (en)
        acc <= acc + d;
end
endmodule
